<?php
 namespace League\CommonMark\Block\Element; use League\CommonMark\Cursor; class BlockQuote extends AbstractBlock { public function canContain(AbstractBlock $block): bool { return true; } public function isCode(): bool { return false; } public function matchesNextLine(Cursor $cursor): bool { if (!$cursor->isIndented() && $cursor->getNextNonSpaceCharacter() === '>') { $cursor->advanceToNextNonSpaceOrTab(); $cursor->advanceBy(1); $cursor->advanceBySpaceOrTab(); return true; } return false; } public function shouldLastLineBeBlank(Cursor $cursor, int $currentLineNumber): bool { return false; } } 